noncompliant:
// Noncompliant - only private constructor, cannot be instantiated
public class MyClass
{
    private MyClass()
    {
    }

    public void DoSomething()
    {
        // ...
    }
}

compliant:
// Option 1: Add a public constructor
public class MyClass
{
    public MyClass()
    {
    }

    private MyClass(int x) // Additional private overload is fine
    {
    }
}

// Option 2: Singleton pattern (exception to the rule)
public class Singleton
{
    private static readonly Singleton instance = new Singleton();

    private Singleton()
    {
    }

    public static Singleton Instance => instance;
}

// Option 3: Static utility class
public static class UtilityClass
{
    public static void DoSomething()
    {
        // ...
    }
}
